function normalizeUrl(u) {
  u = u.trim();

  u = u.split(/[\]\)\>\"\'\s]/)[0];

  u = u.replace(/[.,;:]+$/g, "");

  if (!/^https?:\/\//i.test(u) && /^[a-z0-9.-]+\.[a-z]{2,}(\/|$)/i.test(u)) {
    u = "http://" + u;
  }
  return u;
}

const re = /https?:\/\/[^\s"'<>]+|(?:\b[a-z0-9.-]+\.[a-z]{2,}(?:\/[^\s"'<>]*)?)/gi;

const items = $input.all();

const allUrls = [];

for (const item of items) {
  const email = item.json.email || {};
  const candidates = [email.text]
    .filter(Boolean)
    .join("\n\n");

  const found = (candidates.match(re) || [])
    .map(normalizeUrl)
    .filter(Boolean)
    .filter(u => !/\.(png|jpe?g|gif|webp|svg)(\?|$)/i.test(u))
    .filter(u => !/\/pixel\/tracking\//i.test(u));

  allUrls.push(...found);
}

const urls = [...new Set(allUrls)];

return [
  {
    json: { urls }
  }
];
